import React, { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart as RechartsLineChart, Line } from 'recharts';
import { TrendingUp, Calendar, BarChart3, PieChart, LineChart, Users, CreditCard, Target, ArrowUp, ArrowDown, Minus, StickyNote } from 'lucide-react';
import Card from './Card';

const METRICS = [
  { key: 'registered_onboarded', label: 'Registered Onboarded', icon: Users, color: '#3B82F6' },
  { key: 'linked_accounts', label: 'Linked Accounts', icon: CreditCard, color: '#10B981' },
  { key: 'total_advance_applications', label: 'Total Advance Applications', icon: Target, color: '#F59E0B' },
  { key: 'total_advance_applicants', label: 'Total Advance Applicants', icon: Users, color: '#8B5CF6' },
  { key: 'total_micro_financing_applications', label: 'Total Micro Financing Applications', icon: Target, color: '#EF4444' },
  { key: 'total_micro_financing_applicants', label: 'Total Micro Financing Applicants', icon: Users, color: '#06B6D4' },
  { key: 'total_personal_finance_application', label: 'Total Personal Finance Applications', icon: Target, color: '#84CC16' },
  { key: 'total_personal_finance_applicants', label: 'Total Personal Finance Applicants', icon: Users, color: '#F97316' }
];

// Analytics API calls
const analyticsApi = {
  getDailyWeeklyAnalysis: async (params: any) => {
    const searchParams = new URLSearchParams();
    if (params.weeks) searchParams.append('weeks', params.weeks);
    if (params.months) searchParams.append('months', params.months);
    if (params.metric) searchParams.append('metric', params.metric);
    if (params.startDate) searchParams.append('startDate', params.startDate);
    if (params.endDate) searchParams.append('endDate', params.endDate);
    
    const response = await fetch(`/api/analytics/daily-weekly?${searchParams}`);
    if (!response.ok) throw new Error('Failed to fetch daily/weekly analysis');
    return response.json();
  },
  
  getDayNotes: async (date: string) => {
    const response = await fetch(`/api/notes/day/${date}`);
    if (!response.ok) throw new Error('Failed to fetch day notes');
    return response.json();
  }
};

const DailyWeeklyAnalysis: React.FC = () => {
  const [selectedWeeks, setSelectedWeeks] = useState(['all']);
  const [selectedMonths, setSelectedMonths] = useState<string[]>([]);
  const [selectedMetric, setSelectedMetric] = useState('total_advance_applicants');
  const [selectAllMonths, setSelectAllMonths] = useState(true);
  const [chartType, setChartType] = useState<'bar' | 'line' | 'heatmap'>('bar');
  const [selectedDate, setSelectedDate] = useState<string>('');
  const [analysisView, setAnalysisView] = useState<'weekly' | 'daily' | 'heatmap'>('weekly');

  const { data, isLoading, error } = useQuery({
    queryKey: ['daily-weekly-analysis', selectedWeeks, selectedMonths, selectedMetric, analysisView],
    queryFn: () => analyticsApi.getDailyWeeklyAnalysis({
      weeks: selectedWeeks.includes('all') ? 'all' : selectedWeeks.join(','),
      months: selectAllMonths ? undefined : selectedMonths.join(','),
      metric: selectedMetric,
      view: analysisView
    })
  });

  const { data: dayNotes } = useQuery({
    queryKey: ['day-notes', selectedDate],
    queryFn: () => selectedDate ? analyticsApi.getDayNotes(selectedDate) : null,
    enabled: !!selectedDate
  });

  const handleWeekToggle = (week: string) => {
    if (week === 'all') {
      setSelectedWeeks(['all']);
    } else {
      setSelectedWeeks(prev => {
        const withoutAll = prev.filter(w => w !== 'all');
        if (withoutAll.includes(week)) {
          const newSelection = withoutAll.filter(w => w !== week);
          return newSelection.length === 0 ? ['all'] : newSelection;
        } else {
          return [...withoutAll, week];
        }
      });
    }
  };

  const handleMonthToggle = (month: string) => {
    setSelectedMonths(prev => 
      prev.includes(month) 
        ? prev.filter(m => m !== month)
        : [...prev, month]
    );
  };

  const formatValue = (value: number): string => {
    if (value >= 1000000) return `${(value / 1000000).toFixed(1)}M`;
    if (value >= 1000) return `${(value / 1000).toFixed(1)}K`;
    return value.toString();
  };

  const getTrendIcon = (change: number) => {
    if (change > 5) return <ArrowUp className="h-4 w-4 text-green-600" />;
    if (change < -5) return <ArrowDown className="h-4 w-4 text-red-600" />;
    return <Minus className="h-4 w-4 text-gray-600" />;
  };

  const getTrendColor = (change: number) => {
    if (change > 5) return 'text-green-600';
    if (change < -5) return 'text-red-600';
    return 'text-gray-600';
  };

  const getWeekdayName = (day: number) => {
    const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
    return days[day];
  };

  if (isLoading) {
    return (
      <Card className="p-6">
        <div className="animate-pulse space-y-4">
          <div className="h-8 bg-gray-200 rounded w-1/3"></div>
          <div className="h-64 bg-gray-200 rounded"></div>
        </div>
      </Card>
    );
  }

  if (error) {
    return (
      <Card className="p-6">
        <div className="text-center text-red-600">
          <p className="font-semibold">Error loading daily/weekly analysis</p>
          <p className="text-sm">{error instanceof Error ? error.message : 'Unknown error occurred'}</p>
        </div>
      </Card>
    );
  }

  if (!data || !data.rows || data.rows.length === 0) {
    return (
      <Card className="p-6">
        <div className="text-center text-gray-500">
          <Calendar className="h-12 w-12 mx-auto mb-3 opacity-50" />
          <p className="font-semibold">No Data Available</p>
          <p className="text-sm">No daily/weekly data found for the selected criteria.</p>
        </div>
      </Card>
    );
  }

  const currentMetric = METRICS.find(m => m.key === selectedMetric);
  const IconComponent = currentMetric?.icon || BarChart3;

  // Calculate weekday statistics for heatmap
  const weekdayStats = data.weekday_breakdown || [];
  const maxWeekdayValue = Math.max(...weekdayStats.map((d: any) => d.avg_value));

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center space-x-3">
        <div className="p-2 bg-blue-500 rounded-lg">
          <Calendar className="h-6 w-6 text-white" />
        </div>
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Daily & Weekly Analysis</h2>
          <p className="text-gray-600">Detailed breakdown with week filters and daily insights</p>
        </div>
      </div>

      {/* Controls */}
      <Card className="p-6">
        <div className="grid grid-cols-1 md:grid-cols-6 gap-4">
          {/* Analysis View Selector */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">View Type</label>
            <select
              value={analysisView}
              onChange={(e) => setAnalysisView(e.target.value as 'weekly' | 'daily' | 'heatmap')}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="weekly">Weekly Breakdown</option>
              <option value="daily">Daily Analysis</option>
              <option value="heatmap">Weekday Heatmap</option>
            </select>
          </div>

          {/* Metric Selector */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Metric</label>
            <select
              value={selectedMetric}
              onChange={(e) => setSelectedMetric(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              {METRICS.map(metric => (
                <option key={metric.key} value={metric.key}>
                  {metric.label}
                </option>
              ))}
            </select>
          </div>

          {/* Chart Type Selector */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Chart Type</label>
            <div className="flex space-x-2">
              <button
                onClick={() => setChartType('bar')}
                className={`p-2 rounded ${chartType === 'bar' ? 'bg-blue-500 text-white' : 'bg-gray-200'}`}
                title="Bar Chart"
              >
                <BarChart3 className="h-4 w-4" />
              </button>
              <button
                onClick={() => setChartType('line')}
                className={`p-2 rounded ${chartType === 'line' ? 'bg-blue-500 text-white' : 'bg-gray-200'}`}
                title="Line Chart"
              >
                <LineChart className="h-4 w-4" />
              </button>
              <button
                onClick={() => setChartType('heatmap')}
                className={`p-2 rounded ${chartType === 'heatmap' ? 'bg-blue-500 text-white' : 'bg-gray-200'}`}
                title="Heatmap"
              >
                <PieChart className="h-4 w-4" />
              </button>
            </div>
          </div>

          {/* Week Selector */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Weeks</label>
            <div className="space-y-1">
              <label className="flex items-center">
                <input
                  type="checkbox"
                  checked={selectedWeeks.includes('all')}
                  onChange={() => handleWeekToggle('all')}
                  className="mr-2"
                />
                All Weeks
              </label>
              {[1, 2, 3, 4].map(week => (
                <label key={week} className="flex items-center">
                  <input
                    type="checkbox"
                    checked={selectedWeeks.includes(week.toString())}
                    onChange={() => handleWeekToggle(week.toString())}
                    className="mr-2"
                  />
                  Week {week}
                </label>
              ))}
            </div>
          </div>

          {/* Month Selector */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Months</label>
            <div className="space-y-1">
              <label className="flex items-center">
                <input
                  type="checkbox"
                  checked={selectAllMonths}
                  onChange={(e) => setSelectAllMonths(e.target.checked)}
                  className="mr-2"
                />
                All Months
              </label>
              {data.available_months?.map((month: string) => (
                <label key={month} className="flex items-center">
                  <input
                    type="checkbox"
                    checked={selectedMonths.includes(month)}
                    onChange={() => handleMonthToggle(month)}
                    disabled={selectAllMonths}
                    className="mr-2"
                  />
                  {month}
                </label>
              ))}
            </div>
          </div>

          {/* Date Selector for Daily Notes */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Select Date</label>
            <input
              type="date"
              value={selectedDate}
              onChange={(e) => setSelectedDate(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
        </div>
      </Card>

      {/* Analysis Content */}
      {analysisView === 'heatmap' && (
        <div className="space-y-6">
          <Card className="p-6">
            <div className="flex items-center space-x-3 mb-6">
              <IconComponent className="h-6 w-6" style={{color: currentMetric?.color}} />
              <h3 className="text-lg font-semibold">Weekday Performance Heatmap</h3>
              <div className="ml-auto text-sm text-gray-500">
                Higher intensity = Better performance
              </div>
            </div>
            
            <div className="grid grid-cols-7 gap-3">
              {weekdayStats.map((day: any, index: number) => {
                const intensity = day.avg_value / maxWeekdayValue;
                const isWeekend = day.weekday === 0 || day.weekday === 6;
                return (
                  <div key={index} className="text-center">
                    <div className={`text-sm font-semibold mb-2 ${isWeekend ? 'text-purple-600' : 'text-gray-700'}`}>
                      {getWeekdayName(day.weekday)}
                    </div>
                    <div
                      className="h-24 rounded-lg flex flex-col items-center justify-center text-white font-semibold shadow-lg transition-transform hover:scale-105 cursor-pointer"
                      style={{
                        backgroundColor: `rgba(59, 130, 246, ${Math.max(0.15, intensity)})`,
                        border: isWeekend ? '2px solid #8B5CF6' : '2px solid transparent',
                      }}
                      title={`${getWeekdayName(day.weekday)}: ${formatValue(day.avg_value)} average from ${day.data_points} days`}
                    >
                      <div className="text-lg font-bold">{formatValue(day.avg_value)}</div>
                      <div className="text-xs opacity-80">avg</div>
                    </div>
                    <div className="text-xs text-gray-500 mt-2">
                      {day.data_points} days
                    </div>
                    <div className="text-xs font-medium mt-1" style={{color: currentMetric?.color}}>
                      {((day.avg_value / (data.total_avg || 1)) * 100).toFixed(0)}% of avg
                    </div>
                  </div>
                );
              })}
            </div>
          </Card>

          {/* Weekday Comparison Chart */}
          <Card className="p-6">
            <div className="flex items-center space-x-3 mb-6">
              <BarChart3 className="h-6 w-6 text-blue-600" />
              <h3 className="text-lg font-semibold">Weekday Performance Comparison</h3>
            </div>
            
            <div className="h-64">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={weekdayStats}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis 
                    dataKey="weekday"
                    tick={{fontSize: 12}}
                    tickFormatter={(value) => getWeekdayName(value).slice(0, 3)}
                  />
                  <YAxis tick={{fontSize: 12}} />
                  <Tooltip 
                    formatter={(value: any) => [formatValue(value), 'Average']}
                    labelFormatter={(value) => getWeekdayName(value)}
                  />
                  <Bar 
                    dataKey="avg_value" 
                    fill={currentMetric?.color}
                    radius={[4, 4, 0, 0]}
                  />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </Card>

          {/* Weekday Insights */}
          <Card className="p-6">
            <h4 className="text-lg font-semibold mb-4">Weekday Insights</h4>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {weekdayStats.length > 0 && (
                <>
                  <div className="bg-green-50 border border-green-200 rounded-lg p-4">
                    <div className="flex items-center space-x-2">
                      <TrendingUp className="h-5 w-5 text-green-600" />
                      <div>
                        <p className="text-sm font-medium text-green-800">Best Day</p>
                        <p className="text-lg font-bold text-green-900">
                          {getWeekdayName(weekdayStats.reduce((best: any, current: any) => 
                            current.avg_value > best.avg_value ? current : best
                          ).weekday)}
                        </p>
                        <p className="text-xs text-green-600">
                          {formatValue(Math.max(...weekdayStats.map((d: any) => d.avg_value)))} avg
                        </p>
                      </div>
                    </div>
                  </div>
                  
                  <div className="bg-red-50 border border-red-200 rounded-lg p-4">
                    <div className="flex items-center space-x-2">
                      <ArrowDown className="h-5 w-5 text-red-600" />
                      <div>
                        <p className="text-sm font-medium text-red-800">Lowest Day</p>
                        <p className="text-lg font-bold text-red-900">
                          {getWeekdayName(weekdayStats.reduce((worst: any, current: any) => 
                            current.avg_value < worst.avg_value ? current : worst
                          ).weekday)}
                        </p>
                        <p className="text-xs text-red-600">
                          {formatValue(Math.min(...weekdayStats.map((d: any) => d.avg_value)))} avg
                        </p>
                      </div>
                    </div>
                  </div>
                  
                  <div className="bg-purple-50 border border-purple-200 rounded-lg p-4">
                    <div className="flex items-center space-x-2">
                      <Calendar className="h-5 w-5 text-purple-600" />
                      <div>
                        <p className="text-sm font-medium text-purple-800">Weekend vs Weekday</p>
                        <p className="text-lg font-bold text-purple-900">
                          {(() => {
                            const weekendAvg = weekdayStats.filter((d: any) => d.weekday === 0 || d.weekday === 6)
                              .reduce((sum: number, d: any) => sum + d.avg_value, 0) / 
                              weekdayStats.filter((d: any) => d.weekday === 0 || d.weekday === 6).length;
                            const weekdayAvg = weekdayStats.filter((d: any) => d.weekday !== 0 && d.weekday !== 6)
                              .reduce((sum: number, d: any) => sum + d.avg_value, 0) / 
                              weekdayStats.filter((d: any) => d.weekday !== 0 && d.weekday !== 6).length;
                            const diff = ((weekendAvg - weekdayAvg) / weekdayAvg * 100);
                            return `${diff > 0 ? '+' : ''}${diff.toFixed(1)}%`;
                          })()}
                        </p>
                        <p className="text-xs text-purple-600">Weekend difference</p>
                      </div>
                    </div>
                  </div>
                </>
              )}
            </div>
          </Card>
        </div>
      )}

      {/* Chart View */}
      {analysisView !== 'heatmap' && (
        <Card className="p-6">
          <div className="flex items-center justify-between mb-6">
            <div className="flex items-center space-x-3">
              <IconComponent className="h-6 w-6" style={{color: currentMetric?.color}} />
              <h3 className="text-lg font-semibold">
                {analysisView === 'weekly' ? 'Weekly' : 'Daily'} {currentMetric?.label}
              </h3>
            </div>
            <div className="text-sm text-gray-500">
              {data.rows.length} {analysisView === 'weekly' ? 'weeks' : 'days'} • {selectedWeeks.includes('all') ? 'All weeks' : `Week ${selectedWeeks.join(', ')}`}
            </div>
          </div>

          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              {chartType === 'line' ? (
                <RechartsLineChart data={data.rows}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis 
                    dataKey={analysisView === 'weekly' ? 'week' : 'date'} 
                    tick={{fontSize: 12}}
                    tickFormatter={analysisView === 'daily' ? 
                      (value) => {
                        const date = new Date(value);
                        return `${date.getMonth() + 1}/${date.getDate()} (${getWeekdayName(date.getDay()).slice(0, 3)})`;
                      } : undefined
                    }
                    angle={analysisView === 'daily' ? -45 : 0}
                    textAnchor={analysisView === 'daily' ? 'end' : 'middle'}
                    height={analysisView === 'daily' ? 60 : 30}
                  />
                  <YAxis tick={{fontSize: 12}} />
                  <Tooltip 
                    formatter={(value: any) => [formatValue(value), currentMetric?.label]}
                    labelFormatter={(label) => {
                      if (analysisView === 'daily') {
                        const date = new Date(label);
                        return `${date.toLocaleDateString()} (${getWeekdayName(date.getDay())})`;
                      }
                      return `${analysisView === 'weekly' ? 'Week' : 'Date'}: ${label}`;
                    }}
                  />
                  <Line 
                    type="monotone" 
                    dataKey="value" 
                    stroke={currentMetric?.color}
                    strokeWidth={2}
                    dot={{fill: currentMetric?.color, strokeWidth: 2}}
                  />
                </RechartsLineChart>
              ) : (
                <BarChart data={data.rows}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis 
                    dataKey={analysisView === 'weekly' ? 'week' : 'date'} 
                    tick={{fontSize: 12}}
                    tickFormatter={analysisView === 'daily' ? 
                      (value) => {
                        const date = new Date(value);
                        return `${date.getMonth() + 1}/${date.getDate()} (${getWeekdayName(date.getDay()).slice(0, 3)})`;
                      } : undefined
                    }
                    angle={analysisView === 'daily' ? -45 : 0}
                    textAnchor={analysisView === 'daily' ? 'end' : 'middle'}
                    height={analysisView === 'daily' ? 60 : 30}
                  />
                  <YAxis tick={{fontSize: 12}} />
                  <Tooltip 
                    formatter={(value: any) => [formatValue(value), currentMetric?.label]}
                    labelFormatter={(label) => {
                      if (analysisView === 'daily') {
                        const date = new Date(label);
                        return `${date.toLocaleDateString()} (${getWeekdayName(date.getDay())})`;
                      }
                      return `${analysisView === 'weekly' ? 'Week' : 'Date'}: ${label}`;
                    }}
                  />
                  <Bar 
                    dataKey="value" 
                    fill={currentMetric?.color}
                    radius={[4, 4, 0, 0]}
                  />
                </BarChart>
              )}
            </ResponsiveContainer>
          </div>

          {/* Daily View Additional Info */}
          {analysisView === 'daily' && data.rows.length > 0 && (
            <div className="mt-6 grid grid-cols-2 md:grid-cols-4 gap-4">
              <div className="bg-blue-50 border border-blue-200 rounded-lg p-3">
                <div className="text-sm font-medium text-blue-800">Total Days</div>
                <div className="text-lg font-bold text-blue-900">{data.rows.length}</div>
              </div>
              <div className="bg-green-50 border border-green-200 rounded-lg p-3">
                <div className="text-sm font-medium text-green-800">Best Day</div>
                <div className="text-lg font-bold text-green-900">
                  {(() => {
                    const bestDay = data.rows.reduce((best: any, current: any) => 
                      current.value > best.value ? current : best
                    );
                    const date = new Date(bestDay.date);
                    return getWeekdayName(date.getDay()).slice(0, 3);
                  })()}
                </div>
                <div className="text-xs text-green-600">
                  {formatValue(Math.max(...data.rows.map((d: any) => d.value)))}
                </div>
              </div>
              <div className="bg-red-50 border border-red-200 rounded-lg p-3">
                <div className="text-sm font-medium text-red-800">Lowest Day</div>
                <div className="text-lg font-bold text-red-900">
                  {(() => {
                    const worstDay = data.rows.reduce((worst: any, current: any) => 
                      current.value < worst.value ? current : worst
                    );
                    const date = new Date(worstDay.date);
                    return getWeekdayName(date.getDay()).slice(0, 3);
                  })()}
                </div>
                <div className="text-xs text-red-600">
                  {formatValue(Math.min(...data.rows.map((d: any) => d.value)))}
                </div>
              </div>
              <div className="bg-gray-50 border border-gray-200 rounded-lg p-3">
                <div className="text-sm font-medium text-gray-800">Average</div>
                <div className="text-lg font-bold text-gray-900">
                  {formatValue(data.rows.reduce((sum: number, d: any) => sum + d.value, 0) / data.rows.length)}
                </div>
              </div>
            </div>
          )}
        </Card>
      )}

      {/* Selected Date Notes */}
      {selectedDate && dayNotes && (
        <Card className="p-6">
          <div className="flex items-center space-x-3 mb-4">
            <div className="p-2 bg-yellow-500 rounded-lg">
              <StickyNote className="h-5 w-5 text-white" />
            </div>
            <h4 className="text-lg font-semibold text-gray-900">Notes for {selectedDate}</h4>
          </div>
          
          {dayNotes.notes && dayNotes.notes.length > 0 ? (
            <div className="space-y-3">
              {dayNotes.notes.map((note: any, index: number) => (
                <div key={index} className="bg-yellow-50 border border-yellow-200 rounded-lg p-4">
                  <div className="flex items-start justify-between">
                    <div className="flex-1">
                      <p className="text-gray-800">{note.content}</p>
                      {note.category && (
                        <span className="inline-block mt-2 px-2 py-1 bg-yellow-200 text-yellow-800 text-xs rounded-full">
                          {note.category}
                        </span>
                      )}
                    </div>
                    <div className="text-xs text-gray-500 ml-4">
                      {new Date(note.created_at).toLocaleTimeString()}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center text-gray-500 py-8">
              <StickyNote className="h-12 w-12 mx-auto mb-3 opacity-50" />
              <p>No notes found for this date</p>
            </div>
          )}
        </Card>
      )}

      {/* Weekly Summary (only in weekly view) */}
      {analysisView === 'weekly' && data.weekly_summary && (
        <Card className="p-6">
          <h4 className="text-lg font-semibold mb-4">Weekly Performance Summary</h4>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="bg-green-50 border border-green-200 rounded-lg p-4">
              <div className="flex items-center space-x-2">
                <TrendingUp className="h-5 w-5 text-green-600" />
                <div>
                  <p className="text-sm font-medium text-green-800">Best Week</p>
                  <p className="text-lg font-bold text-green-900">Week {data.weekly_summary.best_week.week}</p>
                  <p className="text-xs text-green-600">{formatValue(data.weekly_summary.best_week.value)}</p>
                </div>
              </div>
            </div>
            
            <div className="bg-red-50 border border-red-200 rounded-lg p-4">
              <div className="flex items-center space-x-2">
                <ArrowDown className="h-5 w-5 text-red-600" />
                <div>
                  <p className="text-sm font-medium text-red-800">Worst Week</p>
                  <p className="text-lg font-bold text-red-900">Week {data.weekly_summary.worst_week.week}</p>
                  <p className="text-xs text-red-600">{formatValue(data.weekly_summary.worst_week.value)}</p>
                </div>
              </div>
            </div>
            
            <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
              <div className="flex items-center space-x-2">
                <BarChart3 className="h-5 w-5 text-blue-600" />
                <div>
                  <p className="text-sm font-medium text-blue-800">Average</p>
                  <p className="text-lg font-bold text-blue-900">{formatValue(data.weekly_summary.avg_value)}</p>
                  <p className="text-xs text-blue-600">across {data.weekly_summary.total_weeks} weeks</p>
                </div>
              </div>
            </div>
          </div>
        </Card>
      )}
    </div>
  );
};

export default DailyWeeklyAnalysis;
